import java.util.HashMap;
import java.util.Map;

class StockPrice {

    public StockPrice() {
        priceMap = new HashMap<>();
        timestampMap = new HashMap<>();
        maxPrice = Integer.MIN_VALUE;
        minPrice = Integer.MAX_VALUE;
        latestTimestamp = 0;
    }

    public void update(int timestamp, int price) {
        if (priceMap.containsKey(timestamp)) {
            int oldPrice = priceMap.get(timestamp);
            maxPrice = Math.max(maxPrice, oldPrice);
            minPrice = Math.min(minPrice, oldPrice);
            timestampMap.put(timestamp, timestampMap.get(timestamp) - 1);
        }
        priceMap.put(timestamp, price);
        maxPrice = Math.max(maxPrice, price);
        minPrice = Math.min(minPrice, price);
        timestampMap.put(timestamp, timestampMap.getOrDefault(timestamp, 0) + 1);
        latestTimestamp = Math.max(latestTimestamp, timestamp);
    }

    public int current() {
        return priceMap.get(latestTimestamp);
    }

    public int maximum() {
        return maxPrice;
    }

    public int minimum() {
        return minPrice;
    }

    private Map<Integer, Integer> priceMap;
    private Map<Integer, Integer> timestampMap;
    private int maxPrice;
    private int minPrice;
    private int latestTimestamp;
}
```

